func (s *server) CreateTransaction(ctx context.Context, req *pb.CreateTransactionRequest) (*pb.CreateTransactionResponse, error) {
	s.mu.Lock()
	defer s.mu.Unlock()

	log.Printf("Received CreateTransaction request: From=%s, To=%s, Amount=%.2f %s",
		req.GetFromAccountId(), req.GetToAccountId(), req.GetAmount(), req.GetCurrency())

	if req.GetAmount() <= 0 {
		return nil, status.Errorf(codes.InvalidArgument, "transaction amount must be positive")
	}

	fromBalance, ok := s.accountBalances[req.GetFromAccountId()]
	if !ok {
		return nil, status.Errorf(codes.NotFound, "source account %s not found", req.GetFromAccountId())
	}

	if fromBalance < req.GetAmount() {
		// For simplicity, we return a FAILED status instead of a gRPC error for insufficient funds
		return &pb.CreateTransactionResponse{
			TransactionId: fmt.Sprintf("txn-%d", rand.Int63n(1e9)), // Generate a temporary ID
			Status:        pb.CreateTransactionResponse_FAILED,
			Message:       "insufficient funds",
		}, nil
	}

	// Deduct from source
	s.accountBalances[req.GetFromAccountId()] -= req.GetAmount()

	// Add to target. If target account doesn't exist, create it with the transferred amount.
	if _, exists := s.accountBalances[req.GetToAccountId()]; !exists {
		s.accountBalances[req.GetToAccountId()] = 0.0
	}
	s.accountBalances[req.GetToAccountId()] += req.GetAmount()

	transactionID := fmt.Sprintf("txn-%d-%s", time.Now().UnixNano(), req.GetFromAccountId())
	s.transactions[transactionID] = req // Store transaction details (mock)

	log.Printf("Transaction %s completed: %s -> %s, Amount: %.2f",
		transactionID, req.GetFromAccountId(), req.GetToAccountId(), req.GetAmount())

	return &pb.CreateTransactionResponse{
		TransactionId: transactionID,
		Status:        pb.CreateTransactionResponse_COMPLETED,
		Message:       "transaction completed successfully",
	}, nil
}

